UPDATE Language_RU_RU
SET Text = 'Позволяет городам строить [COLOR_POSITIVE_TEXT]Атомные бомбы[ENDCOLOR] и [COLOR_POSITIVE_TEXT]Ядерные ракеты[ENDCOLOR].[NEWLINE][NEWLINE]Если вы [COLOR_POSITIVE_TEXT]Первые[ENDCOLOR], кто завершит этот проект, получите [COLOR_POSITIVE_TEXT]Бесплатную[ENDCOLOR] Атомную бомбу и [COLOR_POSITIVE_TEXT]Бесплатную[ENDCOLOR] Исследовательскую лабораторию в [ICON_CAPITAL] столице.'
