UPDATE Language_RU_RU
SET Text = 'Глобальное гражданство — это идея о том, что все люди имеют права и гражданские обязанности, связанные с членством в Мире, с философией и чувствительностью всего мира, а не в качестве гражданина конкретной нации или места. Идея заключается в том, что личность человека выходит за рамки географии или политических границ, а обязанности или права проистекают из членства в более широком классе: человечестве. Это не означает, что такой человек отрекается или отказывается от своей национальности или других, более локальных идентичностей, но такие идентичности занимают второе место по отношению к его членству в глобальном сообществе. В расширенном смысле эта идея приводит к вопросам о состоянии глобального общества в эпоху глобализации. В общем использовании термин может иметь почти то же значение, что и мировой гражданин или космополит, но он также имеет дополнительные специализированные значения в различных контекстах. Различные организации, такие как Всемирная служба власти, выступают за глобальное гражданство.'
WHERE Tag = 'TXT_KEY_PROJECT_UTOPIA_PROJECT_PEDIA';
